    pub const SHADER_STRING: &str = r#"
struct CameraUniform {
    clip_from_world_row0_: vec4<f32>,
    clip_from_world_row1_: vec4<f32>,
    clip_from_world_row2_: vec4<f32>,
    clip_from_world_row3_: vec4<f32>,
}

struct VertexInput {
    @location(0) world_position: vec4<f32>,
    @location(1) color: vec4<f32>,
    @location(2) normal_color: vec4<f32>,
    @location(3) feature_color: vec4<f32>,
    @location(4) pick_color: vec4<f32>,
}

struct VertexOutput {
    @builtin(position) position: vec4<f32>,
    @location(0) color: vec4<f32>,
    @location(1) normal_color: vec4<f32>,
    @location(2) feature_color: vec4<f32>,
    @location(3) pick_color: vec4<f32>,
}

struct FragmentOutput {
    @location(0) color: vec4<f32>,
    @location(1) normal_color: vec4<f32>,
    @location(2) feature_color: vec4<f32>,
    @location(3) pick_color: vec4<f32>,
}

@group(0) @binding(0) 
var<uniform> camera: CameraUniform;

@vertex 
fn vs_main(input: VertexInput) -> VertexOutput {
    var out: VertexOutput;

    let _e5 = camera.clip_from_world_row0_;
    let _e10 = camera.clip_from_world_row1_;
    let _e15 = camera.clip_from_world_row2_;
    let _e20 = camera.clip_from_world_row3_;
    out.position = vec4<f32>(dot(_e5, input.world_position), dot(_e10, input.world_position), dot(_e15, input.world_position), dot(_e20, input.world_position));
    out.color = input.color;
    out.normal_color = input.normal_color;
    out.feature_color = input.feature_color;
    out.pick_color = input.pick_color;
    let _e32 = out;
    return _e32;
}

@fragment 
fn fs_main(input_1: VertexOutput) -> FragmentOutput {
    var out_1: FragmentOutput;

    out_1.color = input_1.color;
    out_1.normal_color = input_1.normal_color;
    out_1.feature_color = input_1.feature_color;
    out_1.pick_color = input_1.pick_color;
    let _e10 = out_1;
    return _e10;
}
"#;
